import { useState, useCallback } from 'react';
import { api } from '../utils/api';

// Crypto symbols that should use region=crypto for chart data
const CRYPTO_SYMBOLS = new Set([
  'BTC', 'ETH', 'SOL', 'AVAX', 'ARB', 'AAVE', 'BNB', 'CRV', 'LINK', 'DOT',
  'ADA', 'ATOM', 'NEAR', 'SUI', 'XRP', 'LTC', 'DOGE', 'MATIC', 'UNI', 'FIL',
  'APT', 'OP', 'INJ', 'TIA', 'SEI', 'RENDER', 'FET', 'AGIX', 'OCEAN',
  'PEPE', 'SHIB', 'BONK', 'WIF', 'FLOKI', 'MEME',
  'MKR', 'COMP', 'SNX', 'SUSHI', 'YFI', 'BAL', 'AAVE',
  'SAND', 'MANA', 'AXS', 'ENJ', 'GALA', 'IMX',
  'GRT', 'FIL', 'AR', 'STORJ', 'SC',
  'ALGO', 'XTZ', 'EOS', 'FLOW', 'EGLD', 'HBAR',
  'ANKR', 'APE', 'ALT', 'BLUR', '1000SATS',
]);

function isCrypto(symbol) {
  if (!symbol) return false;
  const base = symbol.split(/[-/]/)[0].toUpperCase();
  return CRYPTO_SYMBOLS.has(base);
}

export default function useChartData() {
  const [chartData, setChartData] = useState(null);
  const [indicators, setIndicators] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const fetchChart = useCallback(async (symbol, timeframe, region) => {
    if (!symbol) return;
    setLoading(true);
    setError(null);

    const encodedSymbol = encodeURIComponent(symbol);
    const tf = timeframe || '1D';
    // Auto-detect crypto region if not explicitly provided
    const resolvedRegion = region || (isCrypto(symbol) ? 'crypto' : 'us');
    const regionParam = '&region=' + encodeURIComponent(resolvedRegion);

    try {
      const [ohlcvData, indicatorsData] = await Promise.allSettled([
        api('/charts/ohlcv/' + encodedSymbol + '?timeframe=' + encodeURIComponent(tf) + '&bars=500' + regionParam),
        api('/charts/indicators/' + encodedSymbol + '?indicators=sma,rsi,macd' + regionParam),
      ]);

      const ohlcv = ohlcvData.status === 'fulfilled' ? ohlcvData.value : null;
      const indData = indicatorsData.status === 'fulfilled' ? indicatorsData.value : null;

      if (ohlcv) {
        // API returns {symbol, region, timeframe, bars: [...]}
        // ChartsPage expects chartData.bars or chartData.data
        setChartData(ohlcv);
        setError(null);
      } else {
        setChartData(null);
        setError('Failed to load chart data — check API connection');
      }

      if (indData) {
        setIndicators(indData);
      }
    } catch (e) {
      setChartData(null);
      setError(e?.message || 'Failed to load chart data');
    }

    setLoading(false);
  }, []);

  return { chartData, indicators, loading, error, fetchChart };
}
